fn main() {
    let s1: &str = "hello";
    let s2: String = s1.to_string();
    let s3: String = String::from("world");
    let s4: &str = s3.as_str();

    println!("{} {} {} {}", s1, s2, s3, s4);
    // hello hello world world
    println!("{}", s2.len());  // 5
}

