fn main() {
    let s = "hello";
    for c in s.chars() {
        print!("{} ", c);
    }
    println!();  // h e l l o

    let chars: Vec<char> = s.chars().collect();
    println!("{}", chars[0]);  // h
    println!("{}", chars.len());  // 5
}

