fn main() {
    let name = "Rust";
    let version = 2024;
    let msg = format!("{} v{}", name, version);
    println!("{}", msg);  // Rust v2024

    let mut built = String::new();
    for i in 1..=3 {
        if !built.is_empty() {
            built.push_str(", ");
        }
        built.push_str(&i.to_string());
    }
    println!("{}", built);  // 1, 2, 3
}

